function arr_where($src,&$p){$from=isset($src['tgl_awal'])&&$src['tgl_awal']!==''?$src['tgl_awal']:date('Y-m-01');$to=isset($src['tgl_akhir'])&&$src['tgl_akhir']!==''?$src['tgl_akhir']:date('Y-m-t');$w=" WHERE a.attendance_date BETWEEN ? AND ? ";array_push($p,$from,$to);foreach(array('employee_id','shift_id','work_location_id') as $k){if(isset($src[$k])&&$src[$k]!==''){$w.=" AND a.$k=? ";$p[]=(int)$src[$k];}}foreach(array('department_code','attendance_type','attendance_status','attendance_source') as $k){if(isset($src[$k])&&$src[$k]!==''){$w.=" AND a.$k=? ";$p[]=$src[$k];}}$ex=isset($src['exception_type'])?$src['exception_type']:'';if($ex==='LATE')$w.=" AND a.late_minutes>0 ";elseif($ex==='EARLY_LEAVE')$w.=" AND a.early_leave_minutes>0 ";elseif($ex==='OVERTIME')$w.=" AND a.overtime_hours>0 ";elseif($ex==='ABSENCE')$w.=" AND a.attendance_type IN ('ABSENT','SICK','LEAVE') ";elseif($ex==='NO_CLOCK_OUT')$w.=" AND a.actual_clock_in IS NOT NULL AND a.actual_clock_out IS NULL ";if(isset($src['keyword'])&&$src['keyword']!==''){$kw='%'.$src['keyword'].'%';$w.=" AND (a.attendance_no LIKE ? OR a.employee_no LIKE ? OR e.full_name LIKE ? OR a.sap_reference LIKE ? OR a.remarks LIKE ? OR d.nm_dept LIKE ?) ";for($i=0;$i<6;$i++)$p[]=$kw;}return $w;}
