clock_in,$r->actual_clock_out,$r->break_minutes,$r->planned_hours,$r->actual_hours,$r->late_minutes,$r->early_leave_minutes,$r->overtime_hours,$r->attendance_type,$r->attendance_source,$r->attendance_status,$r->absence_reason,$r->correction_reason,$r->remarks,$r->sap_reference,$r->updated_by?:$r->created_by);foreach($vals as $i=>$v)$sheet->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).$rn,$v);$rn++;}erpkb_excel_apply_standard_style($excel,array('sheet'=>$sheet,'title'=>erp_export_title('ATTENDANCE REPORT'),'header_row'=>4,'first_data_row'=>5,'last_data_row'=>max(5,$rn-1),'column_count'=>count($heads),'decimal_columns'=>array('M','N','Q'),'numeric_columns'=>array('L','O','P'),'filters'=>array('Date'=>arr_g('tgl_awal',date('Y-m-01')).' s/d '.arr_g('tgl_akhir',date('Y-m-t'))),'widths'=>array('B'=>20,'D'=>30,'E'=>26,'F'=>24,'G'=>26,'U'=>24,'V'=>28,'W'=>36)));$tmp=erpkb_excel_temp_file('attendance_report_');PHPExcel_IOFactory::createWriter($excel,'Excel2007')->save($tmp);$size=@filesize($tmp);$sig=@file_get_contents($tmp,false,null,0,2);if(!$size||$sig!=='PK'){@unlink($tmp);while(ob_get_level()>$initial)ob_end_clean();echo erp_t('export_excel_invalid_file','File Excel gagal dibuat dengan benar.');exit;}while(ob_get_level()>$initial)ob_end_clean();header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');header('Content-Disposition: attachment; filename="attendance_report_'.date('Ymd_His').'.xlsx"');header('Content-Length: '.$size);header('Cache-Control: max-age=0');header('Pragma: public');readfile($tmp);@unlink($tmp);exit;
